const MODELS = {
    Vertices: "data:model/gltf-binary;base64,",
    Arestas: "data:model/gltf-binary;base64,",
    Face: "data:model/gltf-binary;base64,",
    Centro: "data:model/gltf-binary;base64,",
  };

  const DESCS = {
    Vertices: "Pontos nos cantos (compartilhados por 8 células). Em contagem por frações, cada um vale 1/8.",
    Arestas: "Pontos no meio das arestas (compartilhados por 4 células). Em contagem por frações, cada um vale 1/4.",
    Face: "Pontos no centro das faces (compartilhados por 2 células). Em contagem por frações, cada um vale 1/2.",
    Centro: "Ponto no centro do corpo (pertence só a essa célula). Em contagem por frações, vale 1.",
  };

  const mv = document.getElementById('mv');
  
  mv.autoRotate = false;
const pick = document.getElementById('pick');
const desc = document.getElementById('desc');
  const reset = document.getElementById('reset');

  function applyModel(key){
    mv.src = MODELS[key];
    desc.textContent = DESCS[key] || "";
  }

  pick.addEventListener('change', ()=> applyModel(pick.value));

  reset.addEventListener('click', ()=>{ mv.resetTurntableRotation(); mv.jumpCameraToGoal(); });

  
  applyModel(pick.value);
